import { exec } from 'child_process';
import { promisify } from 'util';
import path from 'path';

const execAsync = promisify(exec);
const REPOS_DIR = '/var/app/repos';

interface CloneOptions {
  repoUrl: string;
  branch?: string;
  depth?: number;
}

export class GitService {
  async cloneRepository(options: CloneOptions): Promise<string> {
    const { repoUrl, branch, depth } = options;
    const repoName = repoUrl.split('/').pop()?.replace('.git', '') || 'repo';
    const targetDir = path.join(REPOS_DIR, repoName);

    let cmd = `git clone ${repoUrl} ${targetDir}`;

    if (branch) {
      cmd += ` --branch ${branch}`;
    }
    if (depth) {
      cmd += ` --depth ${depth}`;
    }

    await execAsync(cmd);
    return targetDir;
  }

  async getCommitLog(repoPath: string, author?: string): Promise<string> {
    const baseCmd = `git -C ${repoPath} log --oneline -20`;
    const cmd = author ? `${baseCmd} --author="${author}"` : baseCmd;

    const { stdout } = await execAsync(cmd);
    return stdout;
  }
}
